import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;

import java.lang.reflect.Field;
import java.lang.reflect.Modifier;

public class CSVFormatTest {

    private void setFinalField(Object target, String fieldName, Object value) throws Exception {
        Field field = CSVFormat.class.getDeclaredField(fieldName);
        field.setAccessible(true);

        // Remove final modifier
        Field modifiersField = Field.class.getDeclaredField("modifiers");
        modifiersField.setAccessible(true);
        modifiersField.setInt(field, field.getModifiers() & ~Modifier.FINAL);

        // Set the new value
        field.set(target, value);
    }

    @Test
    public void testGetHeaderWhenHeaderIsNull() throws Exception {
        CSVFormat csvFormat = CSVFormat.DEFAULT;
        // Using reflection to set header to null explicitly
        setFinalField(csvFormat, "header", null);

        String[] header = csvFormat.getHeader();
        assertNull(header, "Expected header to be null when internal header field is null");
    }

    @Test
    public void testGetHeaderReturnsCloneNotSameInstance() throws Exception {
        CSVFormat csvFormat = CSVFormat.DEFAULT;
        // Prepare header array
        String[] internalHeader = new String[] { "col1", "col2", "col3" };
        // Using reflection to set header field
        setFinalField(csvFormat, "header", internalHeader);

        String[] returnedHeader = csvFormat.getHeader();

        assertNotNull(returnedHeader, "Returned header should not be null");
        assertArrayEquals(internalHeader, returnedHeader, "Returned header should have same contents as internal header");
        assertNotSame(internalHeader, returnedHeader, "Returned header should be a clone, not the same instance");
    }
}
